/**
 * @summary List ledger entries (filterable by mission, action, time range). Read-only — the ledger is append-only.
 */
export const getListLedgerEntriesUrl = (params?: ListLedgerEntriesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ledger?${stringifiedParams}`
    : `/api/ledger`;
};

export const listLedgerEntries = async (
  params?: ListLedgerEntriesParams,
  options?: RequestInit,
): Promise<LedgerPage> => {
  return customFetch<LedgerPage>(getListLedgerEntriesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListLedgerEntriesQueryKey = (
  params?: ListLedgerEntriesParams,
) => {
  return [`/api/ledger`, ...(params ? [params] : [])] as const;
};

export const getListLedgerEntriesQueryOptions = <
  TData = Awaited<ReturnType<typeof listLedgerEntries>>,
  TError = ErrorType<unknown>,
>(
  params?: ListLedgerEntriesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listLedgerEntries>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListLedgerEntriesQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listLedgerEntries>>
  > = ({ signal }) => listLedgerEntries(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listLedgerEntries>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

